def test_export_csv_rate_limit_boundary_returns_429_on_exceeding_limit(
    hr_admin_token, reset_rate_limit, api_client, RATE_LIMIT_MAX
):
    reset_rate_limit(hr_admin_token)
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    url = "/api/employees/export.csv"

    for i in range(RATE_LIMIT_MAX):
        r = api_client.get(url, headers=headers)
        assert r.status_code == 200, f"Request {i+1} expected 200, got {r.status_code}"

    over_limit = api_client.get(url, headers=headers)
    assert over_limit.status_code == 429
    assert "Retry-After" in over_limit.headers

def test_export_csv_decision_table_all_employees_opted_out_all_pii_redacted(
    hr_admin_token, seed_all_opted_out_employees, api_client
):
    resp = api_client.get(
        "/api/employees/export.csv",
        headers={"Authorization": f"Bearer {hr_admin_token}"},
    )
    assert resp.status_code == 200
    assert "text/csv" in resp.headers.get("Content-Type", "")

    rows = <parse_csv_response>(resp.text)
    data_rows = rows[1:]  # skip header
    assert len(data_rows) == len(seed_all_opted_out_employees)

    for row in data_rows:
        for pii_field in ("email", "phone", "address"):
            assert row[pii_field] == "REDACTED", (
                f"Expected REDACTED for {pii_field}, got {row[pii_field]!r}"
            )
        assert row["employee_id"] != "" and row["employee_id"] != "REDACTED"
